namespace Algorithms.Graph.AStarBidirectional
{
    public class AStarBidirectional
    {
        private class Node : IComparable<Node>
        {
            public int r, c;
            public int f, g;

            public int CompareTo(Node other)
            {
                return f.CompareTo(other.f);
            }
        }

        public static int Solve(int[] arr)
        {
            if (arr == null || arr.Length < 7) return -1;

            int rows = arr[0];
            int cols = arr[1];
            int sr = arr[2], sc = arr[3];
            int er = arr[4], ec = arr[5];
            int numObs = arr[6];

            if (arr.Length < 7 + 2 * numObs) return -1;

            if (sr < 0 || sr >= rows || sc < 0 || sc >= cols || er < 0 || er >= rows || ec < 0 || ec >= cols) return -1;
            if (sr == er && sc == ec) return 0;

            bool[,] grid = new bool[rows, cols];
            for (int i = 0; i < numObs; i++)
            {
                int r = arr[7 + 2 * i];
                int c = arr[7 + 2 * i + 1];
                if (r >= 0 && r < rows && c >= 0 && c < cols)
                {
                    grid[r, c] = true;
                }
            }

            if (grid[sr, sc] || grid[er, ec]) return -1;

            var openF = new PriorityQueue<Node, int>();
            var openB = new PriorityQueue<Node, int>();

            int[,] gF = new int[rows, cols];
            int[,] gB = new int[rows, cols];

            for(int r=0; r<rows; r++)
                for(int c=0; c<cols; c++)
                {
                    gF[r,c] = int.MaxValue;
                    gB[r,c] = int.MaxValue;
                }

            int startH = Math.Abs(sr - er) + Math.Abs(sc - ec);
            gF[sr, sc] = 0;
            openF.Enqueue(new Node { r = sr, c = sc, f = startH, g = 0 }, startH);

            int endH = Math.Abs(er - sr) + Math.Abs(ec - sc);
            gB[er, ec] = 0;
            openB.Enqueue(new Node { r = er, c = ec, f = endH, g = 0 }, endH);

            int bestPath = int.MaxValue;
            int[] dr = { -1, 1, 0, 0 };
            int[] dc = { 0, 0, -1, 1 };

            while (openF.Count > 0 && openB.Count > 0)
            {
                // Forward
                if (openF.Count > 0)
                {
                    Node u = openF.Dequeue();
                    if (u.g <= gF[u.r, u.c])
                    {
                        for (int i = 0; i < 4; i++)
                        {
                            int nr = u.r + dr[i];
                            int nc = u.c + dc[i];

                            if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !grid[nr, nc])
                            {
                                int newG = u.g + 1;
                                if (newG < gF[nr, nc])
                                {
                                    gF[nr, nc] = newG;
                                    int h = Math.Abs(nr - er) + Math.Abs(nc - ec);
                                    openF.Enqueue(new Node { r = nr, c = nc, f = newG + h, g = newG }, newG + h);

                                    if (gB[nr, nc] != int.MaxValue)
                                    {
                                        bestPath = Math.Min(bestPath, newG + gB[nr, nc]);
                                    }
                                }
                            }
                        }
                    }
                }

                // Backward
                if (openB.Count > 0)
                {
                    Node u = openB.Dequeue();
                    if (u.g <= gB[u.r, u.c])
                    {
                        for (int i = 0; i < 4; i++)
                        {
                            int nr = u.r + dr[i];
                            int nc = u.c + dc[i];

                            if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !grid[nr, nc])
                            {
                                int newG = u.g + 1;
                                if (newG < gB[nr, nc])
                                {
                                    gB[nr, nc] = newG;
                                    int h = Math.Abs(nr - sr) + Math.Abs(nc - sc);
                                    openB.Enqueue(new Node { r = nr, c = nc, f = newG + h, g = newG }, newG + h);

                                    if (gF[nr, nc] != int.MaxValue)
                                    {
                                        bestPath = Math.Min(bestPath, newG + gF[nr, nc]);
                                    }
                                }
                            }
                        }
                    }
                }

                int minF = openF.Count > 0 ? openF.Peek().f : int.MaxValue;
                int minB = openB.Count > 0 ? openB.Peek().f : int.MaxValue;

                if (bestPath != int.MaxValue && (long)minF + minB >= bestPath) break;
            }

            return bestPath == int.MaxValue ? -1 : bestPath;
        }
    }
}

package astarbidirectional

import (
	"container/heap"
	"math"
)

type Node struct {
	r, c int
	f, g int
	index int
}

type PriorityQueue []*Node

func (pq PriorityQueue) Len() int { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].f < pq[j].f
}
func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}
func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*Node)
	item.index = n
	*pq = append(*pq, item)
}
func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	old[n-1] = nil
	item.index = -1
	*pq = old[0 : n-1]
	return item
}

func AStarBidirectional(arr []int) int {
	if len(arr) < 7 {
		return -1
	}

	rows := arr[0]
	cols := arr[1]
	sr, sc := arr[2], arr[3]
	er, ec := arr[4], arr[5]
	numObs := arr[6]

	if len(arr) < 7+2*numObs {
		return -1
	}

	if sr < 0 || sr >= rows || sc < 0 || sc >= cols || er < 0 || er >= rows || ec < 0 || ec >= cols {
		return -1
	}
	if sr == er && sc == ec {
		return 0
	}

	grid := make([]bool, rows*cols)
	for i := 0; i < numObs; i++ {
		r := arr[7+2*i]
		c := arr[7+2*i+1]
		if r >= 0 && r < rows && c >= 0 && c < cols {
			grid[r*cols+c] = true
		}
	}

	if grid[sr*cols+sc] || grid[er*cols+ec] {
		return -1
	}

	openF := &PriorityQueue{}
	heap.Init(openF)
	openB := &PriorityQueue{}
	heap.Init(openB)

	gF := make([]int, rows*cols)
	gB := make([]int, rows*cols)
	for i := range gF {
		gF[i] = math.MaxInt32
		gB[i] = math.MaxInt32
	}

	hStart := abs(sr-er) + abs(sc-ec)
	gF[sr*cols+sc] = 0
	heap.Push(openF, &Node{r: sr, c: sc, f: hStart, g: 0})

	hEnd := abs(er-sr) + abs(ec-sc)
	gB[er*cols+ec] = 0
	heap.Push(openB, &Node{r: er, c: ec, f: hEnd, g: 0})

	bestPath := math.MaxInt32
	dr := []int{-1, 1, 0, 0}
	dc := []int{0, 0, -1, 1}

	for openF.Len() > 0 && openB.Len() > 0 {
		// Forward
		if openF.Len() > 0 {
			u := heap.Pop(openF).(*Node)
			if u.g <= gF[u.r*cols+u.c] {
				for i := 0; i < 4; i++ {
					nr, nc := u.r+dr[i], u.c+dc[i]
					if nr >= 0 && nr < rows && nc >= 0 && nc < cols && !grid[nr*cols+nc] {
						newG := u.g + 1
						if newG < gF[nr*cols+nc] {
							gF[nr*cols+nc] = newG
							h := abs(nr-er) + abs(nc-ec)
							heap.Push(openF, &Node{r: nr, c: nc, f: newG + h, g: newG})

							if gB[nr*cols+nc] != math.MaxInt32 {
								if newG+gB[nr*cols+nc] < bestPath {
									bestPath = newG + gB[nr*cols+nc]
								}
							}
						}
					}
				}
			}
		}

		// Backward
		if openB.Len() > 0 {
			u := heap.Pop(openB).(*Node)
			if u.g <= gB[u.r*cols+u.c] {
				for i := 0; i < 4; i++ {
					nr, nc := u.r+dr[i], u.c+dc[i]
					if nr >= 0 && nr < rows && nc >= 0 && nc < cols && !grid[nr*cols+nc] {
						newG := u.g + 1
						if newG < gB[nr*cols+nc] {
							gB[nr*cols+nc] = newG
							h := abs(nr-sr) + abs(nc-sc)
							heap.Push(openB, &Node{r: nr, c: nc, f: newG + h, g: newG})

							if gF[nr*cols+nc] != math.MaxInt32 {
								if newG+gF[nr*cols+nc] < bestPath {
									bestPath = newG + gF[nr*cols+nc]
								}
							}
						}
					}
				}
			}
		}

		minF := math.MaxInt32
		if openF.Len() > 0 {
			minF = (*openF)[0].f
		}
		minB := math.MaxInt32
		if openB.Len() > 0 {
			minB = (*openB)[0].f
		}

		if bestPath != math.MaxInt32 && minF+minB >= bestPath {
			break
		}
	}

	if bestPath == math.MaxInt32 {
		return -1
	}
	return bestPath
}

