  if (arr.length < 7) return -1;

  const rows = arr[0];
  const cols = arr[1];
  const sr = arr[2], sc = arr[3];
  const er = arr[4], ec = arr[5];
  const numObs = arr[6];

  if (arr.length < 7 + 2 * numObs) return -1;

  if (sr < 0 || sr >= rows || sc < 0 || sc >= cols || er < 0 || er >= rows || ec < 0 || ec >= cols) return -1;
  if (sr === er && sc === ec) return 0;

  const grid: boolean[][] = Array.from({ length: rows }, () => Array(cols).fill(false));
  for (let i = 0; i < numObs; i++) {
    const r = arr[7 + 2 * i];
    const c = arr[7 + 2 * i + 1];
    if (r >= 0 && r < rows && c >= 0 && c < cols) {
      grid[r][c] = true;
    }
  }

  if (grid[sr][sc] || grid[er][ec]) return -1;

  const openF = new MinHeap<Node>((a, b) => a.f - b.f);
  const openB = new MinHeap<Node>((a, b) => a.f - b.f);

  const gF: number[][] = Array.from({ length: rows }, () => Array(cols).fill(Number.MAX_SAFE_INTEGER));
  const gB: number[][] = Array.from({ length: rows }, () => Array(cols).fill(Number.MAX_SAFE_INTEGER));

  const hStart = Math.abs(sr - er) + Math.abs(sc - ec);
  gF[sr][sc] = 0;
  openF.push({ r: sr, c: sc, f: hStart, g: 0 });

  const hEnd = Math.abs(er - sr) + Math.abs(ec - sc);
  gB[er][ec] = 0;
  openB.push({ r: er, c: ec, f: hEnd, g: 0 });

  let bestPath = Number.MAX_SAFE_INTEGER;
  const dr = [-1, 1, 0, 0];
  const dc = [0, 0, -1, 1];

  while (!openF.isEmpty() && !openB.isEmpty()) {
    // Forward
    if (!openF.isEmpty()) {
      const u = openF.pop()!;
      if (u.g <= gF[u.r][u.c]) {
        for (let i = 0; i < 4; i++) {
          const nr = u.r + dr[i];
          const nc = u.c + dc[i];

          if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !grid[nr][nc]) {
            const newG = u.g + 1;
            if (newG < gF[nr][nc]) {
              gF[nr][nc] = newG;
              const h = Math.abs(nr - er) + Math.abs(nc - ec);
              openF.push({ r: nr, c: nc, f: newG + h, g: newG });

              if (gB[nr][nc] !== Number.MAX_SAFE_INTEGER) {
                bestPath = Math.min(bestPath, newG + gB[nr][nc]);
              }
            }
          }
        }
      }
    }

    // Backward
    if (!openB.isEmpty()) {
      const u = openB.pop()!;
      if (u.g <= gB[u.r][u.c]) {
        for (let i = 0; i < 4; i++) {
          const nr = u.r + dr[i];
          const nc = u.c + dc[i];

          if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !grid[nr][nc]) {
            const newG = u.g + 1;
            if (newG < gB[nr][nc]) {
              gB[nr][nc] = newG;
              const h = Math.abs(nr - sr) + Math.abs(nc - sc);
              openB.push({ r: nr, c: nc, f: newG + h, g: newG });

              if (gF[nr][nc] !== Number.MAX_SAFE_INTEGER) {
                bestPath = Math.min(bestPath, newG + gF[nr][nc]);
              }
            }
          }
        }
      }
    }

    const minF = openF.peek()?.f ?? Number.MAX_SAFE_INTEGER;
    const minB = openB.peek()?.f ?? Number.MAX_SAFE_INTEGER;

    if (bestPath !== Number.MAX_SAFE_INTEGER && minF + minB >= bestPath) break;
  }

  return bestPath === Number.MAX_SAFE_INTEGER ? -1 : bestPath;
}

export function aStarBidirectional(data: number[]): number {
    const rows = data[0], cols = data[1];
    const srcR = data[2], srcC = data[3];
    const dstR = data[4], dstC = data[5];
    const numBlocked = data[6];

    const blocked = new Set<number>();
    let idx = 7;
    for (let i = 0; i < numBlocked; i++) {
        blocked.add(data[idx] * cols + data[idx + 1]);
        idx += 2;
    }

    if (srcR === dstR && srcC === dstC) return 0;
    if (blocked.has(srcR * cols + srcC) || blocked.has(dstR * cols + dstC)) return -1;

    const dirs = [[0, 1], [0, -1], [1, 0], [-1, 0]];
    const h = (r: number, c: number, tr: number, tc: number) => Math.abs(r - tr) + Math.abs(c - tc);

    // Simple BFS-based bidirectional for correctness
    const distF = new Map<number, number>();
    const distB = new Map<number, number>();
    const qF: number[][] = [[srcR, srcC]];
    const qB: number[][] = [[dstR, dstC]];
    distF.set(srcR * cols + srcC, 0);
    distB.set(dstR * cols + dstC, 0);

    let best = Infinity;

    while (qF.length > 0 || qB.length > 0) {
        // Forward
        const nextF: number[][] = [];
        for (const [r, c] of qF) {
            const key = r * cols + c;
            const g = distF.get(key)!;
            if (distB.has(key)) {
                best = Math.min(best, g + distB.get(key)!);
            }
            for (const [dr, dc] of dirs) {
                const nr = r + dr, nc = c + dc;
                const nk = nr * cols + nc;
                if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !blocked.has(nk) && !distF.has(nk)) {
                    distF.set(nk, g + 1);
                    nextF.push([nr, nc]);
                }
            }
        }
        qF.length = 0;
        qF.push(...nextF);

        if (best < Infinity) return best;

        // Backward
        const nextB: number[][] = [];
        for (const [r, c] of qB) {
            const key = r * cols + c;
            const g = distB.get(key)!;
            if (distF.has(key)) {
                best = Math.min(best, g + distF.get(key)!);
            }
            for (const [dr, dc] of dirs) {
                const nr = r + dr, nc = c + dc;
                const nk = nr * cols + nc;
                if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !blocked.has(nk) && !distB.has(nk)) {
                    distB.set(nk, g + 1);
                    nextB.push([nr, nc]);
                }
            }
        }
        qB.length = 0;
        qB.push(...nextB);

        if (best < Infinity) return best;
    }

    return best === Infinity ? -1 : best;
}
